import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { useSocket } from '../../contexts/SocketContext';
import axios from 'axios';
import './AdminPages.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const AdminRatings = () => {
  const { user } = useAuth();
  const { socket } = useSocket();
  const [ratings, setRatings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    average: 0,
    total: 0,
    suggestions: 0,
    issues: 0,
    pendingReplies: 0
  });
  const [selectedRating, setSelectedRating] = useState(null);
  const [replyText, setReplyText] = useState('');
  const [sendingReply, setSendingReply] = useState(false);
  const [filter, setFilter] = useState('all');
  const [notification, setNotification] = useState(null);
  const [pagination, setPagination] = useState({
    page: 1,
    total: 0,
    pages: 1
  });

  useEffect(() => {
    fetchRatings();
    fetchStats();

    if (socket) {
      socket.on('new_machine_rating', (data) => {
        setNotification({
          type: 'new',
          message: `New ${data.type} from ${data.user.name}: ${data.rating} stars`,
          data
        });
        fetchRatings();
        fetchStats();
        
        // Play sound
        const audio = new Audio('/notification.mp3');
        audio.play().catch(() => {});
        
        // Browser notification
        if (Notification.permission === 'granted') {
          new Notification('New Machine Rating', {
            body: `${data.user.name} rated ${data.rating} stars - ${data.type}`,
            icon: '/logo192.png'
          });
        }
      });

      return () => {
        socket.off('new_machine_rating');
      };
    }

    if (Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, [socket, filter, pagination.page]);

  useEffect(() => {
    if (notification) {
      const timer = setTimeout(() => setNotification(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [notification]);

  const fetchRatings = async () => {
    try {
      const response = await axios.get(`${API_URL}/ratings/machine/admin/all`, {
        params: {
          type: filter !== 'all' ? filter : undefined,
          page: pagination.page
        }
      });
      setRatings(response.data.data || []);
      setPagination(response.data.pagination || {
        total: response.data.data?.length || 0,
        page: 1,
        pages: 1
      });
    } catch (error) {
      console.error('Error fetching ratings:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get(`${API_URL}/ratings/machine/stats`);
      setStats(response.data.data);
      
      // Get pending replies count
      const pendingResponse = await axios.get(`${API_URL}/ratings/machine/admin/all?type=pending`);
      const pendingCount = pendingResponse.data.data?.filter(r => !r.adminReply).length || 0;
      setStats(prev => ({ ...prev, pendingReplies: pendingCount }));
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const handleReply = async (ratingId) => {
    if (!replyText.trim()) return;

    setSendingReply(true);
    try {
      await axios.post(`${API_URL}/ratings/machine/${ratingId}/reply`, {
        reply: replyText
      });
      
      setSelectedRating(null);
      setReplyText('');
      fetchRatings();
      fetchStats();
      
      setNotification({
        type: 'success',
        message: 'Reply sent successfully'
      });
    } catch (error) {
      console.error('Error sending reply:', error);
      setNotification({
        type: 'error',
        message: 'Failed to send reply'
      });
    } finally {
      setSendingReply(false);
    }
  };

  const getStarDisplay = (rating) => {
    return '★'.repeat(rating) + '☆'.repeat(5 - rating);
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getTypeIcon = (type) => {
    return type === 'suggestion' ? '💡' : '⚠️';
  };

  return (
    <div className="admin-page-container">
      {/* Notification Toast */}
      {notification && (
        <div className={`notification-toast ${notification.type}`}>
          <span className="notification-icon">
            {notification.type === 'new' ? '⭐' : 
             notification.type === 'success' ? '✅' : '❌'}
          </span>
          <span className="notification-message">{notification.message}</span>
          <button className="notification-close" onClick={() => setNotification(null)}>×</button>
        </div>
      )}

      {/* Page Header */}
      <div className="page-header">
        <div>
          <h1 className="page-title">Machine Ratings & Feedback</h1>
          <p className="page-description">
            View and respond to customer feedback about the vending machine
            {stats.pendingReplies > 0 && (
              <span className="pending-badge">
                {stats.pendingReplies} pending replies
              </span>
            )}
          </p>
        </div>
        <div className="filter-controls">
          <select 
            value={filter} 
            onChange={(e) => setFilter(e.target.value)}
            className="filter-select"
          >
            <option value="all">All Feedback</option>
            <option value="suggestion">Suggestions Only</option>
            <option value="issue">Issues Only</option>
            <option value="pending">Pending Reply</option>
          </select>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">⭐</div>
          <div className="stat-content">
            <div className="stat-label">Average Rating</div>
            <div className="stat-value success">{stats.average}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">📊</div>
          <div className="stat-content">
            <div className="stat-label">Total Ratings</div>
            <div className="stat-value">{stats.total}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">💡</div>
          <div className="stat-content">
            <div className="stat-label">Suggestions</div>
            <div className="stat-value success">{stats.suggestions}</div>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">⚠️</div>
          <div className="stat-content">
            <div className="stat-label">Issues</div>
            <div className="stat-value warning">{stats.issues}</div>
          </div>
        </div>
      </div>

      {/* Distribution Overview */}
      {stats.total > 0 && (
        <div className="distribution-card">
          <h3>Rating Distribution</h3>
          <div className="distribution-bars">
            {[5, 4, 3, 2, 1].map((star) => {
              // This is simplified - you'd need actual distribution data from API
              const percentage = 20; // Placeholder
              return (
                <div key={star} className="distribution-row">
                  <span className="star-label">{star} ★</span>
                  <div className="bar-container">
                    <div 
                      className="bar-fill"
                      style={{ width: `${percentage}%` }}
                    />
                  </div>
                  <span className="bar-count">0</span>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Ratings List */}
      {loading ? (
        <div className="loading-state">Loading ratings...</div>
      ) : ratings.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">⭐</div>
          <h3>No Ratings Found</h3>
          <p>There are no customer ratings to display.</p>
        </div>
      ) : (
        <div className="ratings-list">
          {ratings.map((rating) => (
            <div key={rating._id} className="rating-admin-card">
              <div className="rating-header">
                <div className="user-info">
                  <span className="user-name">
                    {rating.user?.firstName} {rating.user?.lastName}
                  </span>
                  <span className="user-email">{rating.user?.email}</span>
                </div>
                <div className="rating-meta">
                  <span className={`type-badge ${rating.commentType}`}>
                    {getTypeIcon(rating.commentType)} {rating.commentType}
                  </span>
                  <span className={`status-badge ${rating.adminReply ? 'replied' : 'pending'}`}>
                    {rating.adminReply ? 'Replied' : 'Pending'}
                  </span>
                </div>
              </div>

              <div className="rating-content">
                <div className="rating-stars">
                  <span className="stars">{getStarDisplay(rating.rating)}</span>
                  <span className="rating-value">{rating.rating}/5</span>
                  <span className="rating-date">{formatDate(rating.createdAt)}</span>
                </div>
                
                <div className="comment-box">
                  <p>{rating.comment}</p>
                </div>

                {rating.adminReply && (
                  <div className="admin-reply">
                    <div className="reply-header">
                      <span className="reply-label">Your Reply:</span>
                      <span className="reply-date">{formatDate(rating.repliedAt)}</span>
                    </div>
                    <p>{rating.adminReply}</p>
                  </div>
                )}

                <div className="rating-footer">
                  {!rating.adminReply && (
                    <button 
                      className="btn-reply"
                      onClick={() => setSelectedRating(rating)}
                    >
                      Reply to Customer
                    </button>
                  )}
                  {rating.adminReply && (
                    <span className="replied-by">
                      Replied by: {rating.repliedBy?.firstName} {rating.repliedBy?.lastName}
                    </span>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Pagination */}
      {pagination.pages > 1 && (
        <div className="pagination">
          <button 
            onClick={() => setPagination({ ...pagination, page: pagination.page - 1 })}
            disabled={pagination.page === 1}
            className="pagination-btn"
          >
            Previous
          </button>
          <span className="page-info">
            Page {pagination.page} of {pagination.pages}
          </span>
          <button 
            onClick={() => setPagination({ ...pagination, page: pagination.page + 1 })}
            disabled={pagination.page === pagination.pages}
            className="pagination-btn"
          >
            Next
          </button>
        </div>
      )}

      {/* Reply Modal */}
      {selectedRating && (
        <div className="modal-overlay" onClick={() => setSelectedRating(null)}>
          <div className="modal-container" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Reply to Customer Feedback</h2>
              <button className="modal-close" onClick={() => setSelectedRating(null)}>×</button>
            </div>
            
            <div className="modal-body">
              <div className="customer-info">
                <h4>{selectedRating.user?.firstName} {selectedRating.user?.lastName}</h4>
                <p>{selectedRating.user?.email}</p>
              </div>

              <div className="original-rating">
                <div className="rating-stars">
                  {getStarDisplay(selectedRating.rating)} ({selectedRating.rating}/5)
                </div>
                <div className="rating-type-badge">
                  <span className={`type-badge ${selectedRating.commentType}`}>
                    {getTypeIcon(selectedRating.commentType)} {selectedRating.commentType}
                  </span>
                </div>
                <p className="rating-comment">"{selectedRating.comment}"</p>
                <small>Received: {formatDate(selectedRating.createdAt)}</small>
              </div>

              <div className="reply-form">
                <label className="form-label">Your Reply</label>
                <textarea
                  value={replyText}
                  onChange={(e) => setReplyText(e.target.value)}
                  rows="4"
                  className="form-textarea"
                  placeholder="Type your reply here..."
                  autoFocus
                />
              </div>
            </div>
            
            <div className="modal-footer">
              <button 
                className="btn-secondary" 
                onClick={() => {
                  setSelectedRating(null);
                  setReplyText('');
                }}
              >
                Cancel
              </button>
              <button 
                className="btn-primary" 
                onClick={() => handleReply(selectedRating._id)}
                disabled={!replyText.trim() || sendingReply}
              >
                {sendingReply ? 'Sending...' : 'Send Reply'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminRatings;
